diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..14836a436a65 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2262,7 +2262,74 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
     Function *F = Intrinsic::getOrInsertDeclaration(I.getModule(), InvID, Ty);
     return CallInst::Create(F, {Op0, Z});
   }
-
+  // sub min/max(X + C, Y), min/max(X, Y) --> zext (X pred Y) where C == 1
+  // where add has no signed/unsigned wrap as appropriate.
+  auto *MinMax0 = dyn_cast<MinMaxIntrinsic>(Op0);
+  if (MinMax0 && MinMax0->getIntrinsicID() == MinMax->getIntrinsicID() &&
+      (MinMax0->hasOneUse() || MinMax->hasOneUse())) {
+    Value *A0 = MinMax0->getLHS();
+    Value *B0 = MinMax0->getRHS();
+    Value *A1 = MinMax->getLHS();
+    Value *B1 = MinMax->getRHS();
+    // Try to find the common operand (Y) and the differing operands (X and X+C).
+    Value *X = nullptr, *Y = nullptr;
+    const APInt *C = nullptr;
+    auto CheckPair = [&](Value *L0, Value *R0, Value *L1, Value *R1) -> bool {
+      if (R0 == R1) {
+        Y = R0;
+        if (MinMax0->isSigned()) {
+          if ((match(L0, m_DisjointOr(m_Value(X), m_APInt(C))) ||
+               (match(L0, m_Add(m_Value(X), m_APInt(C))) &&
+                isa<Instruction>(L0) &&
+                cast<Instruction>(L0)->hasNoSignedWrap())) && X == L1)
+            return true;
+          if ((match(L1, m_DisjointOr(m_Value(X), m_APInt(C))) ||
+               (match(L1, m_Add(m_Value(X), m_APInt(C))) &&
+                isa<Instruction>(L1) &&
+                cast<Instruction>(L1)->hasNoSignedWrap())) && X == L0)
+            return true;
+        } else {
+          if ((match(L0, m_DisjointOr(m_Value(X), m_APInt(C))) ||
+               (match(L0, m_Add(m_Value(X), m_APInt(C))) &&
+                isa<Instruction>(L0) &&
+                cast<Instruction>(L0)->hasNoUnsignedWrap())) && X == L1)
+            return true;
+          if ((match(L1, m_DisjointOr(m_Value(X), m_APInt(C))) ||
+               (match(L1, m_Add(m_Value(X), m_APInt(C))) &&
+                isa<Instruction>(L1) &&
+                cast<Instruction>(L1)->hasNoUnsignedWrap())) && X == L0)
+            return true;
+        }
+      }
+      return false;
+    };
+    if (CheckPair(A0, B0, A1, B1) ||
+        CheckPair(B0, A0, A1, B1) ||
+        CheckPair(A0, B0, B1, A1) ||
+        CheckPair(B0, A0, B1, A1)) {
+      if (C && *C == 1) {
+        ICmpInst::Predicate Pred;
+        switch (MinMax0->getIntrinsicID()) {
+        case Intrinsic::smin:
+          Pred = ICmpInst::ICMP_SLT;
+          break;
+        case Intrinsic::smax:
+          Pred = ICmpInst::ICMP_SGE;
+          break;
+        case Intrinsic::umin:
+          Pred = ICmpInst::ICMP_ULT;
+          break;
+        case Intrinsic::umax:
+          Pred = ICmpInst::ICMP_UGE;
+          break;
+        default:
+          llvm_unreachable("unexpected min/max intrinsic");
+        }
+        Value *Cmp = Builder.CreateICmp(Pred, X, Y);
+        return CastInst::CreateZExtOrBitCast(Cmp, Ty);
+      }
+    }
+  }
   return nullptr;
 }

